mapper.select:
SELECT p.photo_id, p.user_id, p.group_id, p.file_path, p.file_name, DATE_FORMAT(p.taken_at, '%Y-%m-%dT%H:%i:%s') AS taken_at, p.location, p.description, p.sort_order, DATE_FORMAT(p.created_at, '%Y-%m-%dT%H:%i:%s') AS created_at, t.tag_id, t.tag_name FROM photos p LEFT JOIN photo_tags pt ON p.photo_id = pt.photo_id LEFT JOIN tags t ON pt.tag_id = t.tag_id WHERE p.user_id = #{userId} AND YEAR(p.taken_at) = #{year} AND MONTH(p.taken_at) = #{month} AND DAY(p.taken_at) = #{day} AND p.group_id = #{groupId}
AND (p.description LIKE CONCAT('%', #{keyword}, '%') OR p.location LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.taken_at DESC, p.photo_id DESC

